static bool em_predict_attack(int total_flow_packets) {
    char command[512];
    int result;

    // Command to call the Python script
    snprintf(command, sizeof(command),
             "python3 %s %s %s",
             python_script_path, data_path, model_path);

    result = system(command);
    return result;

